import{_ as t,o,c as r,a2 as e}from"./chunks/framework.Crpw6aS5.js";const c=JSON.parse('{"title":"弗兰克·普塔克","description":"","frontmatter":{"title":"弗兰克·普塔克"},"headers":[],"relativePath":"04_people/弗兰克·普塔克.md","filePath":"04_people/弗兰克·普塔克.md"}'),n={name:"04_people/弗兰克·普塔克.md"};function l(d,a,h,i,s,u){return o(),r("div",null,[...a[0]||(a[0]=[e('<h1 id="弗兰克·普塔克-frank-ptak" tabindex="-1">弗兰克·普塔克（Frank Ptak） <a class="header-anchor" href="#弗兰克·普塔克-frank-ptak" aria-label="Permalink to &quot;弗兰克·普塔克（Frank Ptak）&quot;">​</a></h1><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>姓名</strong></td><td>Frank Ptak（弗兰克·普塔克）</td></tr><tr><td><strong>职位</strong></td><td>Marmon集团 CEO</td></tr><tr><td><strong>关联公司</strong></td><td>Marmon Group（马蒙集团）</td></tr><tr><td><strong>首次提及</strong></td><td>2007年</td></tr></tbody></table><h2 id="与巴菲特的故事" tabindex="-1">与巴菲特的故事 <a class="header-anchor" href="#与巴菲特的故事" aria-label="Permalink to &quot;与巴菲特的故事&quot;">​</a></h2><p>弗兰克·普塔克是Marmon集团的CEO，与普利兹克家族有着近半个世纪的渊源，2007年伯克希尔收购Marmon 60%股权后继续领导这家拥有130多家企业的工业巨头。</p><h3 id="marmon与普利兹克家族" tabindex="-1">Marmon与普利兹克家族 <a class="header-anchor" href="#marmon与普利兹克家族" aria-label="Permalink to &quot;Marmon与普利兹克家族&quot;">​</a></h3><p>Marmon集团由普利兹克家族经营了近50年，运营着125家企业，分为九个部门，总销售额70亿美元，拥有约20,000名雇员。巴菲特与普利兹克家族的渊源可追溯至1954年：</p><blockquote><p>&quot;杰·普利兹克在1954年的Rockwood巧克力公司股东会上对我很友好……从那以后，我一直热切关注杰的商业交易。&quot;（2007年股东信）</p></blockquote><h3 id="收购过程" tabindex="-1">收购过程 <a class="header-anchor" href="#收购过程" aria-label="Permalink to &quot;收购过程&quot;">​</a></h3><p>巴菲特用他一贯的信任方式完成了交易：</p><blockquote><p>&quot;我们仅仅用Marmon财务报表定价，没雇顾问，也没有吹毛求疵。我知道这家企业就会像普利兹克家族描述的那样，他们也知道我们会准时成交，不管金融市场多么混乱。&quot;（2007年股东信）</p></blockquote><h3 id="管理能力" tabindex="-1">管理能力 <a class="header-anchor" href="#管理能力" aria-label="Permalink to &quot;管理能力&quot;">​</a></h3><blockquote><p>&quot;Marmon CEO弗兰克·普塔克，和长期合作伙伴约翰·尼科尔斯密切合作。约翰以前是伊利诺伊工具工厂（ITW）非常成功的CEO，他和弗兰克一起运营着一堆混合工业业务。看看他们ITW记录，你会印象深刻。&quot;（2007年股东信）</p></blockquote><h3 id="后续发展" tabindex="-1">后续发展 <a class="header-anchor" href="#后续发展" aria-label="Permalink to &quot;后续发展&quot;">​</a></h3><p>2010年，伯克希尔计划将对Marmon的所有权增加到80%，巴菲特对普塔克持续给予高度评价：</p><blockquote><p>&quot;弗兰克·普塔克出色地经营着Marmon，我们期待100%的所有权。&quot;（2010年股东信）</p></blockquote><h2 id="关联年份" tabindex="-1">关联年份 <a class="header-anchor" href="#关联年份" aria-label="Permalink to &quot;关联年份&quot;">​</a></h2><p>2007, 2008, 2010, 2011, 2012</p><h2 id="相关链接" tabindex="-1">相关链接 <a class="header-anchor" href="#相关链接" aria-label="Permalink to &quot;相关链接&quot;">​</a></h2><ul><li><a href="./../03_公司库/Marmon.html">Marmon Group</a> - 管理的公司</li><li><a href="./../03_公司库/伯克希尔哈撒韦.html">伯克希尔·哈撒韦</a> - 母公司</li></ul><hr><p><em>最后更新：2026-04-09</em></p>',22)])])}const m=t(n,[["render",l]]);export{c as __pageData,m as default};
